content='<!DOCTYPE html>\n<html lang="en">\n<head>\n<meta charset="UTF-8">\n<meta name="viewport" content="width=device-width,initial-scale=1.0">\n<title>NNIT Shop</title>\n<link href="https://fonts.googleapis.com/css2?family=Playfair+Display:wght@700;900&family=DM+Sans:wght@400;500;600;700&display=swap" rel="stylesheet">\n<style>\n:root{--bg:#fafaf8;--s:#fff;--s2:#f5f5f0;--br:#e8e4dc;--dk:#1a1a18;--ac:#c8a96e;--ac2:#e8c87e;--rd:#e85d4a;--gn:#4a9e6b;--t:#1a1a18;--t2:#6b6b60;--t3:#a8a89a;--f:\'DM Sans\',sans-serif;--d:\'Playfair Display\',serif}\n*{margin:0;padding:0;box-sizing:border-box}\nbody{background:var(--bg);color:var(--t);font-family:var(--f);min-height:100vh}\n.ann{background:var(--dk);color:var(--ac2);text-align:center;padding:8px;font-size:12px;letter-spacing:2px}\n.top{background:var(--s);border-bottom:1px solid var(--br);padding:0 32px;height:60px;display:flex;align-items:center;justify-content:space-between;position:sticky;top:0;z-index:100}\n.logo{font-family:var(--d);font-size:22px;font-weight:900;cursor:pointer}.logo span{color:var(--ac)}\n.nav a{font-size:13px;font-weight:500;color:var(--t2);cursor:pointer;margin-left:24px;text-decoration:none}\n.nav a:hover{color:var(--t)}\n.ta{display:flex;gap:10px;align-items:center}\n.sbar{display:flex;align-items:center;background:var(--s2);border:1px solid var(--br);border-radius:20px;padding:0 14px;height:36px;gap:6px}\n.sbar input{border:none;background:transparent;outline:none;font-size:13px;font-family:var(--f);color:var(--t);width:200px}\n.sbar input::placeholder{color:var(--t3)}\n.ibtn{height:36px;padding:0 14px;border-radius:20px;border:1px solid var(--br);background:var(--s);cursor:pointer;font-size:12px;font-weight:600;display:flex;align-items:center;gap:4px;transition:all 0.15s;font-family:var(--f)}\n.ibtn:hover{background:var(--dk);color:#fff;border-color:var(--dk)}\n.ibtn .badge{background:var(--rd);color:#fff;font-size:9px;width:16px;height:16px;border-radius:50%;display:flex;align-items:center;justify-content:center}\n.hero{background:var(--dk);color:#fff;padding:70px 32px;display:grid;grid-template-columns:1fr 1fr;gap:40px;align-items:center;min-height:480px}\n.htag{display:inline-block;background:rgba(200,169,110,0.15);color:var(--ac2);border:1px solid rgba(200,169,110,0.3);padding:4px 14px;border-radius:20px;font-size:11px;letter-spacing:2px;margin-bottom:18px}\n.htitle{font-family:var(--d);font-size:52px;line-height:1.1;margin-bottom:14px;font-weight:900}\n.htitle em{color:var(--ac2);font-style:normal}\n.hsub{color:rgba(255,255,255,0.6);font-size:15px;line-height:1.7;margin-bottom:28px;max-width:420px}\n.hbtns{display:flex;gap:10px;flex-wrap:wrap}\n.btn-gold{background:var(--ac);color:var(--dk);border:none;padding:12px 28px;border-radius:8px;font-size:14px;font-family:var(--f);font-weight:700;cursor:pointer;transition:all 0.15s}\n.btn-gold:hover{background:var(--ac2)}\n.btn-out{background:transparent;color:#fff;border:1px solid rgba(255,255,255,0.3);padding:12px 28px;border-radius:8px;font-size:14px;font-family:var(--f);font-weight:600;cursor:pointer}\n.btn-out:hover{border-color:#fff}\n.hbox{background:linear-gradient(135deg,rgba(200,169,110,0.1),rgba(200,169,110,0.03));border:1px solid rgba(200,169,110,0.2);border-radius:16px;height:340px;display:flex;flex-direction:column;align-items:center;justify-content:center;gap:16px}\n.hbox-num{font-family:var(--d);font-size:36px;color:var(--ac2)}\n.hbox-lbl{font-size:11px;color:rgba(255,255,255,0.4);letter-spacing:2px}\n.hstats{display:flex;gap:28px;margin-top:28px}\n.sec{padding:52px 32px}\n.sec-hd{display:flex;justify-content:space-between;align-items:flex-end;margin-bottom:24px}\n.sec-title{font-family:var(--d);font-size:28px;font-weight:900}\n.sec-sub{color:var(--t2);font-size:13px;margin-top:4px}\n.see-all{font-size:13px;color:var(--ac);font-weight:600;cursor:pointer;border:none;background:none;font-family:var(--f)}\n.cat-grid{display:grid;grid-template-columns:repeat(auto-fill,minmax(140px,1fr));gap:12px}\n.cat-card{background:var(--s);border:2px solid var(--br);border-radius:12px;padding:20px 14px;text-align:center;cursor:pointer;transition:all 0.2s}\n.cat-card:hover,.cat-card.active{border-color:var(--ac);background:rgba(200,169,110,0.04)}\n.cat-card:hover{transform:translateY(-2px)}\n.cat-lbl{font-size:14px;font-weight:800;color:var(--ac);font-family:var(--d);margin-bottom:6px}\n.cat-name{font-size:13px;font-weight:600;color:var(--t)}\n.cat-cnt{font-size:11px;color:var(--t3);margin-top:2px}\n.prod-grid{display:grid;grid-template-columns:repeat(auto-fill,minmax(240px,1fr));gap:18px}\n.pcard{background:var(--s);border:1px solid var(--br);border-radius:14px;overflow:hidden;cursor:pointer;transition:all 0.2s;position:relative}\n.pcard:hover{box-shadow:0 10px 36px rgba(0,0,0,0.1);transform:translateY(-2px)}\n.pimg{height:210px;background:var(--s2);position:relative;overflow:hidden}\n.pimg img{width:100%;height:100%;object-fit:cover;display:block}\n.pbadge{position:absolute;top:10px;left:10px;color:#fff;font-size:10px;padding:3px 8px;border-radius:6px;font-weight:700}\n.pbadge.sale{background:var(--rd)}\n.pbadge.hot{background:var(--ac)}\n.pbadge.new{background:var(--gn)}\n.pwish{position:absolute;top:10px;right:10px;width:30px;height:30px;background:#fff;border-radius:50%;display:flex;align-items:center;justify-content:center;font-size:13px;font-weight:700;cursor:pointer;border:1px solid var(--br);transition:all 0.15s}\n.pwish:hover,.pwish.on{background:var(--rd);color:#fff;border-color:var(--rd)}\n.pinfo{padding:14px}\n.pcat{font-size:10px;color:var(--t3);letter-spacing:1px;margin-bottom:3px}\n.pname{font-size:14px;font-weight:600;margin-bottom:6px;line-height:1.4}\n.pstars{color:var(--ac);font-size:12px;font-weight:700}\n.prev{font-size:11px;color:var(--t3);margin-left:4px}\n.pprice{display:flex;align-items:center;gap:8px;margin:8px 0 12px}\n.pcur{font-family:var(--d);font-size:20px;font-weight:700}\n.pold{font-size:13px;color:var(--t3);text-decoration:line-through}\n.psave{font-size:11px;color:var(--gn);font-weight:600}\n.btn-cart{width:100%;background:var(--dk);color:#fff;border:none;padding:10px;border-radius:8px;font-size:13px;font-family:var(--f);font-weight:600;cursor:pointer;transition:all 0.15s}\n.btn-cart:hover{background:var(--ac);color:var(--dk)}\n.filters{display:flex;gap:8px;flex-wrap:wrap;margin-bottom:20px;align-items:center}\n.fbtn{padding:6px 14px;border-radius:20px;border:1px solid var(--br);background:var(--s);color:var(--t2);font-size:12px;cursor:pointer;font-family:var(--f);font-weight:500;transition:all 0.15s}\n.fbtn:hover,.fbtn.active{background:var(--dk);color:#fff;border-color:var(--dk)}\n.fsort{padding:6px 14px;border-radius:20px;border:1px solid var(--br);background:var(--s);color:var(--t2);font-size:12px;font-family:var(--f);outline:none;cursor:pointer;margin-left:auto}\n.cart-ov{position:fixed;inset:0;background:rgba(0,0,0,0.5);z-index:200;backdrop-filter:blur(4px)}\n.cart-sl{position:fixed;right:0;top:0;bottom:0;width:400px;background:var(--s);z-index:201;display:flex;flex-direction:column;box-shadow:-16px 0 48px rgba(0,0,0,0.12);animation:slIn 0.3s ease}\n@keyframes slIn{from{transform:translateX(100%)}to{transform:translateX(0)}}\n.cart-hd{padding:20px 24px;border-bottom:1px solid var(--br);display:flex;justify-content:space-between;align-items:center}\n.cart-title{font-family:var(--d);font-size:20px;font-weight:700}\n.xbtn{width:32px;height:32px;border-radius:50%;border:1px solid var(--br);background:none;cursor:pointer;font-size:16px;display:flex;align-items:center;justify-content:center;transition:all 0.15s}\n.xbtn:hover{background:var(--dk);color:#fff}\n.cart-body{flex:1;overflow-y:auto;padding:16px}\n.citem{display:flex;gap:12px;padding:12px;background:var(--s2);border-radius:10px;margin-bottom:10px}\n.cimg{width:60px;height:60px;border-radius:8px;overflow:hidden;flex-shrink:0}\n.cimg img{width:100%;height:100%;object-fit:cover}\n.cname{font-size:13px;font-weight:600;margin-bottom:4px}\n.cprice{font-size:14px;font-weight:700}\n.qrow{display:flex;align-items:center;gap:8px;margin-top:8px}\n.qbtn{width:24px;height:24px;border-radius:6px;border:1px solid var(--br);background:var(--s);cursor:pointer;font-size:14px;font-weight:700;transition:all 0.15s;display:flex;align-items:center;justify-content:center}\n.qbtn:hover{background:var(--dk);color:#fff}\n.qval{font-size:13px;font-weight:600;min-width:20px;text-align:center}\n.cart-ft{padding:18px 24px;border-top:1px solid var(--br)}\n.cart-tot{display:flex;justify-content:space-between;align-items:center;margin-bottom:14px}\n.cart-tot-l{font-size:14px;color:var(--t2)}\n.cart-tot-v{font-family:var(--d);font-size:24px;font-weight:700}\n.btn-chk{width:100%;background:var(--dk);color:#fff;border:none;padding:13px;border-radius:10px;font-size:15px;font-family:var(--f);font-weight:700;cursor:pointer;margin-bottom:8px;transition:all 0.15s}\n.btn-chk:hover{background:var(--ac);color:var(--dk)}\n.cart-empty{text-align:center;padding:48px 20px}\n.modal-ov{position:fixed;inset:0;background:rgba(0,0,0,0.6);z-index:300;display:flex;align-items:center;justify-content:center;padding:20px;backdrop-filter:blur(6px)}\n.modal{background:var(--s);border-radius:18px;width:720px;max-width:100%;max-height:88vh;overflow-y:auto;position:relative;display:grid;grid-template-columns:1fr 1fr}\n.modal-img{background:var(--s2);border-radius:18px 0 0 18px;overflow:hidden;min-height:380px}\n.modal-img img{width:100%;height:100%;object-fit:cover}\n.modal-info{padding:28px}\n.modal-cat{font-size:11px;color:var(--t3);letter-spacing:2px;margin-bottom:6px}\n.modal-title{font-family:var(--d);font-size:22px;font-weight:700;margin-bottom:10px;line-height:1.3}\n.modal-price{font-family:var(--d);font-size:30px;font-weight:700;margin-bottom:14px}\n.modal-desc{font-size:13px;color:var(--t2);line-height:1.8;margin-bottom:16px}\n.modal-stock{font-size:12px;color:var(--gn);font-weight:600;margin-bottom:16px}\n.mqrow{display:flex;align-items:center;gap:10px;margin-bottom:16px}\n.mqlbl{font-size:13px;font-weight:600}\n.modal-actions{display:flex;flex-direction:column;gap:8px}\n.mcx{position:absolute;top:14px;right:14px;width:32px;height:32px;border-radius:50%;background:#fff;border:1px solid var(--br);cursor:pointer;font-size:14px;display:flex;align-items:center;justify-content:center;z-index:10}\n.bnr{background:linear-gradient(135deg,var(--dk),#2d2d2a);color:#fff;padding:44px 32px;border-radius:16px;margin:0 32px 40px;display:grid;grid-template-columns:1fr auto;gap:28px;align-items:center}\n.bnr-t{font-family:var(--d);font-size:26px;font-weight:900;margin-bottom:6px}\n.bnr-s{color:rgba(255,255,255,0.6);font-size:14px}\n.bnr-row{display:flex;gap:8px;margin-top:14px}\n.bnr-row input{background:rgba(255,255,255,0.1);border:1px solid rgba(255,255,255,0.2);color:#fff;padding:10px 14px;border-radius:8px;font-size:13px;font-family:var(--f);outline:none;flex:1}\n.bnr-row input::placeholder{color:rgba(255,255,255,0.4)}\n.bnr-row button{background:var(--ac);color:var(--dk);border:none;padding:10px 18px;border-radius:8px;font-size:13px;font-family:var(--f);font-weight:700;cursor:pointer}\n.bnr-ico{font-family:var(--d);font-size:48px;color:var(--ac2);text-align:center}\nfooter{background:var(--dk);color:rgba(255,255,255,0.6);padding:44px 32px 22px;margin-top:40px}\n.fg{display:grid;grid-template-columns:2fr 1fr 1fr 1fr;gap:36px;margin-bottom:36px}\n.fb{font-family:var(--d);font-size:20px;color:#fff;margin-bottom:10px}\n.fd{font-size:13px;line-height:1.7}\n.ft{font-size:11px;letter-spacing:2px;color:var(--ac2);margin-bottom:12px}\n.fl{display:block;font-size:13px;color:rgba(255,255,255,0.5);margin-bottom:7px;cursor:pointer}\n.fl:hover{color:#fff}\n.fbot{border-top:1px solid rgba(255,255,255,0.1);padding-top:18px;display:flex;justify-content:space-between;font-size:12px}\n.toast{position:fixed;bottom:22px;right:22px;background:var(--dk);color:#fff;padding:11px 18px;border-radius:10px;font-size:13px;z-index:999;box-shadow:0 6px 20px rgba(0,0,0,0.2)}\n.page-account{max-width:480px;margin:0 auto;padding:52px 32px}\n.page-about{max-width:720px;margin:0 auto;padding:52px 32px}\n.form-field{margin-bottom:12px}\n.form-field label{font-size:11px;color:var(--t2);display:block;margin-bottom:4px;letter-spacing:1px}\n.form-field input{width:100%;background:var(--s2);border:1px solid var(--br);color:var(--t);padding:10px 12px;border-radius:8px;font-size:14px;font-family:var(--f);outline:none}\n.form-field input:focus{border-color:var(--ac)}\n.card-box{background:var(--s2);border-radius:12px;padding:24px;margin-bottom:14px}\n.no-results{text-align:center;padding:60px 20px;grid-column:1/-1}\n.no-results-title{font-family:var(--d);font-size:22px;margin-bottom:8px}\n</style>\n</head>\n<body>\n\n<div class="ann">FREE SHIPPING OVER EUR 50 &nbsp;|&nbsp; USE CODE NNIT10 FOR 10% OFF</div>\n\n<div class="top">\n  <div class="logo" onclick="goHome()">NNIT<span>.</span>SHOP</div>\n  <nav class="nav">\n    <a onclick="goHome()">Home</a>\n    <a onclick="goShop(\'all\')">Shop</a>\n    <a onclick="goShop(\'electronics\')">Electronics</a>\n    <a onclick="goShop(\'fashion\')">Fashion</a>\n    <a onclick="goShop(\'home\')">Home</a>\n    <a onclick="goPage(\'about\')">About</a>\n  </nav>\n  <div class="ta">\n    <div class="sbar">\n      <span style="color:var(--t3)">&#8981;</span>\n      <input type="text" id="search-inp" placeholder="Search products..." oninput="doSearch(this.value)">\n    </div>\n    <button class="ibtn" onclick="goPage(\'account\')">WISHLIST <span id="wc">0</span></button>\n    <button class="ibtn" onclick="openCart()">CART <span class="badge" id="cc">0</span></button>\n  </div>\n</div>\n\n<div id="page"></div>\n\n<div id="cart-ov" style="display:none">\n  <div class="cart-ov" onclick="closeCart()"></div>\n  <div class="cart-sl">\n    <div class="cart-hd">\n      <div class="cart-title">Shopping Cart</div>\n      <button class="xbtn" onclick="closeCart()">&#10005;</button>\n    </div>\n    <div class="cart-body" id="cart-body"></div>\n    <div class="cart-ft" id="cart-ft"></div>\n  </div>\n</div>\n\n<div class="modal-ov" id="modal-ov" style="display:none" onclick="if(event.target===this)closeModal()">\n  <div class="modal">\n    <button class="mcx" onclick="closeModal()">&#10005;</button>\n    <div class="modal-img" id="modal-img"></div>\n    <div class="modal-info" id="modal-info"></div>\n  </div>\n</div>\n\n<script>\nvar PRODUCTS=[\n{id:1,name:"Wireless Headphones",cat:"electronics",img:"https://images.unsplash.com/photo-1505740420928-5e560c06d30e?w=600&q=80",price:89.99,old:129.99,rating:4.8,rv:234,badge:"SALE",desc:"Premium wireless headphones with active noise cancellation. 30-hour battery life, comfortable over-ear design.",stock:15},\n{id:2,name:"Smart Watch Pro",cat:"electronics",img:"https://images.unsplash.com/photo-1523275335684-37898b6baf30?w=600&q=80",price:199.99,old:249.99,rating:4.7,rv:189,badge:"HOT",desc:"Smartwatch with health monitoring, GPS tracking, and 7-day battery life.",stock:8},\n{id:3,name:"4K Action Camera",cat:"electronics",img:"https://images.unsplash.com/photo-1502920917128-1aa500764cbd?w=600&q=80",price:149.99,old:199.99,rating:4.6,rv:156,badge:"SALE",desc:"Waterproof 4K camera with image stabilization. Perfect for sports and adventure.",stock:20},\n{id:4,name:"Bluetooth Speaker",cat:"electronics",img:"https://images.unsplash.com/photo-1608043152269-423dbba4e7e1?w=600&q=80",price:59.99,old:79.99,rating:4.5,rv:312,badge:"",desc:"360-degree surround sound, waterproof IPX7, 24-hour playtime.",stock:30},\n{id:5,name:"Premium Leather Jacket",cat:"fashion",img:"https://images.unsplash.com/photo-1551028719-00167b16eac5?w=600&q=80",price:179.99,old:229.99,rating:4.9,rv:89,badge:"NEW",desc:"Genuine leather jacket with premium stitching. Classic style meets modern design.",stock:12},\n{id:6,name:"Running Shoes Ultra",cat:"fashion",img:"https://images.unsplash.com/photo-1542291026-7eec264c27ff?w=600&q=80",price:119.99,old:159.99,rating:4.7,rv:445,badge:"HOT",desc:"Lightweight running shoes with responsive cushioning and breathable mesh upper.",stock:25},\n{id:7,name:"Designer Sunglasses",cat:"fashion",img:"https://images.unsplash.com/photo-1511499767150-a48a237f0083?w=600&q=80",price:69.99,old:99.99,rating:4.6,rv:167,badge:"SALE",desc:"UV400 protection polarized lenses. Lightweight, scratch-resistant coating.",stock:18},\n{id:8,name:"Cotton T-Shirt Pack x3",cat:"fashion",img:"https://images.unsplash.com/photo-1521572163474-6864f9cf17ab?w=600&q=80",price:34.99,old:49.99,rating:4.4,rv:523,badge:"",desc:"Pack of 3 premium cotton t-shirts. Soft, breathable, available in multiple colors.",stock:50},\n{id:9,name:"Coffee Machine Deluxe",cat:"home",img:"https://images.unsplash.com/photo-1495474472287-4d71bcdd2085?w=600&q=80",price:129.99,old:179.99,rating:4.8,rv:201,badge:"HOT",desc:"Automatic coffee machine with built-in grinder, milk frother and programmable timer.",stock:10},\n{id:10,name:"Air Purifier HEPA",cat:"home",img:"https://images.unsplash.com/photo-1585771724684-38269d6639fd?w=600&q=80",price:89.99,old:119.99,rating:4.7,rv:134,badge:"NEW",desc:"True HEPA filter removes 99.97% of particles. Covers up to 50m2.",stock:14},\n{id:11,name:"Yoga Mat Premium",cat:"sports",img:"https://images.unsplash.com/photo-1601925228897-b7ed5e97c26b?w=600&q=80",price:44.99,old:59.99,rating:4.6,rv:289,badge:"",desc:"Extra thick non-slip yoga mat. Eco-friendly, 6mm joint cushioning.",stock:35},\n{id:12,name:"Protein Shaker Bottle",cat:"sports",img:"https://images.unsplash.com/photo-1593095948071-474c5cc2989d?w=600&q=80",price:19.99,old:29.99,rating:4.5,rv:678,badge:"",desc:"BPA-free shaker bottle, 700ml capacity, leak-proof, dishwasher safe.",stock:100},\n{id:13,name:"Skincare Gift Set",cat:"beauty",img:"https://images.unsplash.com/photo-1556228578-8c89e6adf883?w=600&q=80",price:79.99,old:109.99,rating:4.8,rv:145,badge:"NEW",desc:"Complete skincare set: cleanser, toner, moisturizer and serum. All skin types.",stock:22},\n{id:14,name:"Electric Toothbrush",cat:"beauty",img:"https://images.unsplash.com/photo-1607613009820-a29f7bb81c04?w=600&q=80",price:54.99,old:74.99,rating:4.7,rv:367,badge:"SALE",desc:"Sonic toothbrush with 5 cleaning modes. 2-minute timer, 30-day battery.",stock:28},\n{id:15,name:"Kids Learning Tablet",cat:"kids",img:"https://images.unsplash.com/photo-1585790050230-5dd28404ccb9?w=600&q=80",price:99.99,old:139.99,rating:4.8,rv:256,badge:"HOT",desc:"Educational tablet for kids 3-12. Parental controls, 5000+ learning games.",stock:16},\n{id:16,name:"Board Game Collection",cat:"kids",img:"https://images.unsplash.com/photo-1610890716171-6b1bb98ffd09?w=600&q=80",price:39.99,old:54.99,rating:4.9,rv:178,badge:"NEW",desc:"10 classic board games. Family fun for ages 4 and above.",stock:40},\n];\n\nvar CATS=[\n{id:"all",lbl:"ALL",name:"All Products"},\n{id:"electronics",lbl:"TECH",name:"Electronics"},\n{id:"fashion",lbl:"STYLE",name:"Fashion"},\n{id:"home",lbl:"HOME",name:"Home"},\n{id:"sports",lbl:"SPORT",name:"Sports"},\n{id:"beauty",lbl:"BEAUTY",name:"Beauty"},\n{id:"kids",lbl:"KIDS",name:"Kids"},\n];\n\nvar cart=JSON.parse(localStorage.getItem("nc2")||"[]");\nvar wish=JSON.parse(localStorage.getItem("nw2")||"[]");\nvar curCat="all";\nvar curSort="f";\nvar curSearch="";\nvar mQty=1;\n\nfunction saveCart(){localStorage.setItem("nc2",JSON.stringify(cart));}\nfunction saveWish(){localStorage.setItem("nw2",JSON.stringify(wish));}\nfunction cartCount(){return cart.reduce(function(s,i){return s+i.qty;},0);}\nfunction cartTotal(){return cart.reduce(function(s,i){return s+i.price*i.qty;},0);}\n\nfunction updateBadges(){\n  var cc=document.getElementById("cc");\n  var wc=document.getElementById("wc");\n  if(cc)cc.textContent=cartCount();\n  if(wc)wc.textContent=wish.length;\n}\n\nfunction addToCart(id,qty){\n  qty=qty||1;\n  var p=PRODUCTS.find(function(x){return x.id===id;});\n  if(!p)return;\n  var ex=cart.find(function(x){return x.id===id;});\n  if(ex)ex.qty+=qty;\n  else cart.push({id:p.id,name:p.name,price:p.price,img:p.img,qty:qty});\n  saveCart();updateBadges();\n  showToast(p.name+" added to cart");\n  renderCart();\n}\n\nfunction removeFromCart(id){\n  cart=cart.filter(function(x){return x.id!==id;});\n  saveCart();updateBadges();renderCart();\n}\n\nfunction changeQty(id,d){\n  var i=cart.find(function(x){return x.id===id;});\n  if(!i)return;\n  i.qty+=d;\n  if(i.qty<=0)removeFromCart(id);\n  else{saveCart();renderCart();}\n}\n\nfunction toggleWish(id){\n  var i=wish.indexOf(id);\n  if(i>=0)wish.splice(i,1);\n  else wish.push(id);\n  saveWish();updateBadges();\n}\n\nfunction isWished(id){return wish.indexOf(id)>=0;}\n\nfunction openCart(){\n  document.getElementById("cart-ov").style.display="block";\n  renderCart();\n}\n\nfunction closeCart(){\n  document.getElementById("cart-ov").style.display="none";\n}\n\nfunction renderCart(){\n  var body=document.getElementById("cart-body");\n  var ft=document.getElementById("cart-ft");\n  if(!body)return;\n  if(!cart.length){\n    body.innerHTML=\'<div class="cart-empty"><div style="font-family:var(--d);font-size:20px;margin-bottom:8px">Cart is empty</div><div style="color:var(--t2);font-size:13px">Browse products and add to cart</div></div>\';\n    ft.innerHTML="";\n    return;\n  }\n  body.innerHTML=cart.map(function(item){\n    return \'<div class="citem">\'+\n      \'<div class="cimg"><img src="\'+item.img+\'" alt="\'+item.name+\'"></div>\'+\n      \'<div style="flex:1">\'+\n        \'<div class="cname">\'+item.name+\'</div>\'+\n        \'<div class="cprice">EUR \'+item.price.toFixed(2)+\'</div>\'+\n        \'<div class="qrow">\'+\n          \'<button class="qbtn" onclick="changeQty(\'+item.id+\',-1)">-</button>\'+\n          \'<span class="qval">\'+item.qty+\'</span>\'+\n          \'<button class="qbtn" onclick="changeQty(\'+item.id+\',1)">+</button>\'+\n          \'<button onclick="removeFromCart(\'+item.id+\')" style="margin-left:8px;background:none;border:none;color:var(--rd);cursor:pointer;font-size:12px;font-family:var(--f)">Remove</button>\'+\n        \'</div>\'+\n      \'</div>\'+\n    \'</div>\';\n  }).join("");\n  ft.innerHTML=\n    \'<div class="cart-tot"><span class="cart-tot-l">Total</span><span class="cart-tot-v">EUR \'+cartTotal().toFixed(2)+\'</span></div>\'+\n    \'<button class="btn-chk" onclick="doCheckout()">Checkout Now</button>\'+\n    \'<button onclick="closeCart()" style="width:100%;background:none;border:1px solid var(--br);padding:11px;border-radius:10px;font-size:13px;font-family:var(--f);cursor:pointer;margin-top:0">Continue Shopping</button>\';\n}\n\nfunction doCheckout(){\n  showToast("Checkout - Connect Stripe payment to activate");\n  closeCart();\n}\n\nfunction getFiltered(){\n  var f=PRODUCTS.filter(function(p){\n    var cm=curCat==="all"||p.cat===curCat;\n    var sm=!curSearch||p.name.toLowerCase().indexOf(curSearch.toLowerCase())>=0||p.cat.toLowerCase().indexOf(curSearch.toLowerCase())>=0;\n    return cm&&sm;\n  });\n  if(curSort==="pl")f.sort(function(a,b){return a.price-b.price;});\n  else if(curSort==="ph")f.sort(function(a,b){return b.price-a.price;});\n  else if(curSort==="r")f.sort(function(a,b){return b.rating-a.rating;});\n  return f;\n}\n\nfunction stars(r){\n  var s="";\n  for(var i=0;i<Math.floor(r);i++)s+="&#9733;";\n  return s;\n}\n\nfunction pcard(p){\n  var disc=p.old?Math.round((1-p.price/p.old)*100):0;\n  var w=isWished(p.id);\n  var bc=p.badge==="NEW"?"new":p.badge==="HOT"?"hot":p.badge==="SALE"?"sale":"";\n  return \'<div class="pcard" onclick="openModal(\'+p.id+\')">\'+\n    \'<div class="pimg">\'+\n      \'<img src="\'+p.img+\'" alt="\'+p.name+\'" loading="lazy">\'+\n      (p.badge?\'<div class="pbadge \'+bc+\'">\'+p.badge+\'</div>\':\'\')+\n      \'<div class="pwish\'+(w?" on":"")+\'" onclick="event.stopPropagation();twUI(\'+p.id+\',this)">\'+(w?"H":"W")+\'</div>\'+\n    \'</div>\'+\n    \'<div class="pinfo">\'+\n      \'<div class="pcat">\'+p.cat.toUpperCase()+\'</div>\'+\n      \'<div class="pname">\'+p.name+\'</div>\'+\n      \'<div style="margin-bottom:6px"><span class="pstars">\'+stars(p.rating)+\'</span><span class="prev">(\'+p.rv+\')</span></div>\'+\n      \'<div class="pprice">\'+\n        \'<span class="pcur">EUR \'+p.price.toFixed(2)+\'</span>\'+\n        (p.old?\'<span class="pold">EUR \'+p.old.toFixed(2)+\'</span>\':\'\')+\n        (disc>0?\'<span class="psave">-\'+disc+\'%</span>\':\'\')+\n      \'</div>\'+\n      \'<button class="btn-cart" onclick="event.stopPropagation();addToCart(\'+p.id+\')">Add to Cart</button>\'+\n    \'</div>\'+\n  \'</div>\';\n}\n\nfunction twUI(id,el){\n  toggleWish(id);\n  var w=isWished(id);\n  el.textContent=w?"H":"W";\n  el.classList.toggle("on",w);\n}\n\nfunction openModal(id){\n  var p=PRODUCTS.find(function(x){return x.id===id;});\n  if(!p)return;\n  mQty=1;\n  var disc=p.old?Math.round((1-p.price/p.old)*100):0;\n  document.getElementById("modal-img").innerHTML=\'<img src="\'+p.img+\'" alt="\'+p.name+\'" style="width:100%;height:100%;object-fit:cover">\';\n  document.getElementById("modal-info").innerHTML=\n    \'<div class="modal-cat">\'+p.cat.toUpperCase()+\'</div>\'+\n    \'<div class="modal-title">\'+p.name+\'</div>\'+\n    \'<div style="margin-bottom:10px"><span class="pstars" style="font-size:15px">\'+stars(p.rating)+\'</span><span class="prev">(\'+p.rv+\' reviews)</span></div>\'+\n    \'<div class="modal-price">EUR \'+p.price.toFixed(2)+\n      (p.old?\' <span style="font-size:16px;color:var(--t3);text-decoration:line-through;font-family:var(--f)">EUR \'+p.old.toFixed(2)+\'</span>\':\'\')+\n      (disc>0?\' <span style="font-size:13px;color:var(--gn);font-weight:700">-\'+disc+\'%</span>\':\'\')+\n    \'</div>\'+\n    \'<div class="modal-desc">\'+p.desc+\'</div>\'+\n    \'<div class="modal-stock">In stock: \'+p.stock+\' available</div>\'+\n    \'<div class="mqrow"><span class="mqlbl">Qty:</span>\'+\n      \'<button class="qbtn" onclick="chgMQ(-1)">-</button>\'+\n      \'<span class="qval" id="mqv">1</span>\'+\n      \'<button class="qbtn" onclick="chgMQ(1)">+</button>\'+\n    \'</div>\'+\n    \'<div class="modal-actions">\'+\n      \'<button class="btn-cart" style="padding:13px;font-size:14px" onclick="addToCart(\'+p.id+\',mQty);closeModal()">Add to Cart</button>\'+\n      \'<button onclick="toggleWish(\'+p.id+\');showToast(\\\'Added to wishlist\\\')" style="width:100%;background:none;border:1px solid var(--br);padding:11px;border-radius:8px;font-size:14px;font-family:var(--f);cursor:pointer">+ Add to Wishlist</button>\'+\n    \'</div>\';\n  document.getElementById("modal-ov").style.display="flex";\n}\n\nfunction chgMQ(d){mQty=Math.max(1,mQty+d);var e=document.getElementById("mqv");if(e)e.textContent=mQty;}\nfunction closeModal(){document.getElementById("modal-ov").style.display="none";}\n\nfunction doSearch(val){\n  curSearch=val;\n  goShop(curCat);\n}\n\nfunction goHome(){\n  curSearch="";\n  document.getElementById("search-inp").value="";\n  var featured=PRODUCTS.filter(function(p){return p.badge==="HOT"||p.badge==="NEW";}).slice(0,4);\n  var best=PRODUCTS.slice().sort(function(a,b){return b.rv-a.rv;}).slice(0,4);\n  var html=\n    \'<div class="hero">\'+\n      \'<div>\'+\n        \'<div class="htag">NEW ARRIVALS 2026</div>\'+\n        \'<div class="htitle">Shop The Best<br><em>Deals</em> Online</div>\'+\n        \'<div class="hsub">Discover quality products at competitive prices. Free shipping on orders over EUR 50.</div>\'+\n        \'<div class="hbtns">\'+\n          \'<button class="btn-gold" onclick="goShop(\\\'all\\\')">Shop Now</button>\'+\n          \'<button class="btn-out" onclick="goShop(\\\'electronics\\\')">Electronics</button>\'+\n        \'</div>\'+\n        \'<div class="hstats">\'+\n          \'<div><div class="hbox-num">\'+PRODUCTS.length+\'+</div><div class="hbox-lbl">PRODUCTS</div></div>\'+\n          \'<div><div class="hbox-num">99%</div><div class="hbox-lbl">SATISFACTION</div></div>\'+\n          \'<div><div class="hbox-num">24H</div><div class="hbox-lbl">DELIVERY</div></div>\'+\n        \'</div>\'+\n      \'</div>\'+\n      \'<div class="hbox">\'+\n        \'<div class="hbox-num">NNIT</div>\'+\n        \'<div class="hbox-lbl">ONLINE SHOP</div>\'+\n        \'<div style="color:rgba(255,255,255,0.4);font-size:13px;text-align:center;padding:0 20px">Quality products delivered to your door</div>\'+\n      \'</div>\'+\n    \'</div>\'+\n    \'<div class="sec">\'+\n      \'<div class="sec-hd"><div><div class="sec-title">Shop by Category</div><div class="sec-sub">Browse all departments</div></div><button class="see-all" onclick="goShop(\\\'all\\\')">See All</button></div>\'+\n      \'<div class="cat-grid">\'+\n        CATS.map(function(c){\n          var cnt=c.id==="all"?PRODUCTS.length:PRODUCTS.filter(function(p){return p.cat===c.id;}).length;\n          return \'<div class="cat-card" onclick="goShop(\\\'\'+c.id+\'\\\')">\'+\n            \'<div class="cat-lbl">\'+c.lbl+\'</div>\'+\n            \'<div class="cat-name">\'+c.name+\'</div>\'+\n            \'<div class="cat-cnt">\'+cnt+\' items</div>\'+\n          \'</div>\';\n        }).join("")+\n      \'</div>\'+\n    \'</div>\'+\n    \'<div class="sec" style="background:var(--s2);padding-top:40px;padding-bottom:40px">\'+\n      \'<div class="sec-hd"><div><div class="sec-title">Featured Products</div><div class="sec-sub">Hand picked for you</div></div><button class="see-all" onclick="goShop(\\\'all\\\')">View All</button></div>\'+\n      \'<div class="prod-grid">\'+featured.map(pcard).join("")+\'</div>\'+\n    \'</div>\'+\n    \'<div class="bnr">\'+\n      \'<div>\'+\n        \'<div class="bnr-t">Get 10% Off Your First Order</div>\'+\n        \'<div class="bnr-s">Subscribe to our newsletter for exclusive deals</div>\'+\n        \'<div class="bnr-row"><input type="email" placeholder="Enter your email"><button onclick="showToast(\\\'Subscribed! Check your email.\\\')">Subscribe</button></div>\'+\n      \'</div>\'+\n      \'<div class="bnr-ico">DEALS</div>\'+\n    \'</div>\'+\n    \'<div class="sec">\'+\n      \'<div class="sec-hd"><div><div class="sec-title">Best Sellers</div><div class="sec-sub">Most popular products</div></div><button class="see-all" onclick="goShop(\\\'all\\\')">View All</button></div>\'+\n      \'<div class="prod-grid">\'+best.map(pcard).join("")+\'</div>\'+\n    \'</div>\'+\n    renderFooter();\n  document.getElementById("page").innerHTML=html;\n}\n\nfunction goShop(cat){\n  if(cat)curCat=cat;\n  var f=getFiltered();\n  var catObj=CATS.find(function(c){return c.id===curCat;})||CATS[0];\n  var html=\n    \'<div class="sec">\'+\n      \'<div class="sec-hd"><div>\'+\n        \'<div class="sec-title">\'+(curSearch?\'Search: "\'+curSearch+\'"\':catObj.name)+\'</div>\'+\n        \'<div class="sec-sub">\'+f.length+\' product\'+(f.length!==1?\'s\':\'\')+\' found</div>\'+\n      \'</div></div>\'+\n      \'<div class="filters">\'+\n        CATS.map(function(c){return \'<button class="fbtn\'+(curCat===c.id?\' active\':\'\')+\'" onclick="goShop(\\\'\'+c.id+\'\\\')">\'+c.lbl+\' \'+c.name+\'</button>\';}).join("")+\n        \'<select class="fsort" onchange="curSort=this.value;goShop()">\'+\n          \'<option value="f">Featured</option>\'+\n          \'<option value="pl">Price: Low to High</option>\'+\n          \'<option value="ph">Price: High to Low</option>\'+\n          \'<option value="r">Top Rated</option>\'+\n        \'</select>\'+\n      \'</div>\'+\n      \'<div class="prod-grid">\'+\n        (f.length?f.map(pcard).join(""):\'<div class="no-results"><div class="no-results-title">No products found</div><div style="color:var(--t2)">Try a different search or category</div></div>\')+\n      \'</div>\'+\n    \'</div>\'+renderFooter();\n  document.getElementById("page").innerHTML=html;\n}\n\nfunction goPage(page){\n  if(page==="about"){\n    document.getElementById("page").innerHTML=\n      \'<div class="page-about">\'+\n        \'<div class="sec-title" style="margin-bottom:18px">About NNIT Shop</div>\'+\n        \'<p style="font-size:15px;color:var(--t2);line-height:1.9;margin-bottom:14px">NNIT Shop is your trusted online marketplace for quality products at competitive prices.</p>\'+\n        \'<p style="font-size:15px;color:var(--t2);line-height:1.9;margin-bottom:28px">We ship to 50+ countries and offer 30-day returns on all products.</p>\'+\n        \'<div style="display:grid;grid-template-columns:repeat(3,1fr);gap:16px">\'+\n          \'<div class="card-box" style="text-align:center"><div style="font-family:var(--d);font-size:22px;color:var(--ac);margin-bottom:8px">FAST</div><div style="font-weight:600;margin-bottom:4px">Fast Shipping</div><div style="font-size:13px;color:var(--t2)">24-48 hour delivery</div></div>\'+\n          \'<div class="card-box" style="text-align:center"><div style="font-family:var(--d);font-size:22px;color:var(--ac);margin-bottom:8px">SAFE</div><div style="font-weight:600;margin-bottom:4px">Secure Payments</div><div style="font-size:13px;color:var(--t2)">100% secure checkout</div></div>\'+\n          \'<div class="card-box" style="text-align:center"><div style="font-family:var(--d);font-size:22px;color:var(--ac);margin-bottom:8px">EASY</div><div style="font-weight:600;margin-bottom:4px">Easy Returns</div><div style="font-size:13px;color:var(--t2)">30-day return policy</div></div>\'+\n        \'</div>\'+\n      \'</div>\'+renderFooter();\n  }else if(page==="account"){\n    var wishItems=wish.map(function(id){\n      var p=PRODUCTS.find(function(x){return x.id===id;});\n      if(!p)return "";\n      return \'<div style="display:flex;gap:12px;align-items:center;padding:10px 0;border-bottom:1px solid var(--br)">\'+\n        \'<div style="width:52px;height:52px;border-radius:8px;overflow:hidden"><img src="\'+p.img+\'" style="width:100%;height:100%;object-fit:cover"></div>\'+\n        \'<div style="flex:1"><div style="font-size:13px;font-weight:600">\'+p.name+\'</div><div style="font-size:12px;color:var(--t2)">EUR \'+p.price.toFixed(2)+\'</div></div>\'+\n        \'<button onclick="addToCart(\'+p.id+\')" class="btn-cart" style="width:auto;padding:6px 14px">Add</button>\'+\n      \'</div>\';\n    }).join("");\n    document.getElementById("page").innerHTML=\n      \'<div class="page-account">\'+\n        \'<div class="sec-title" style="margin-bottom:22px">My Account</div>\'+\n        \'<div class="card-box">\'+\n          \'<div style="font-weight:600;margin-bottom:14px">Sign In</div>\'+\n          \'<div class="form-field"><label>EMAIL</label><input type="email" placeholder="your@email.com"></div>\'+\n          \'<div class="form-field"><label>PASSWORD</label><input type="password" placeholder="Password"></div>\'+\n          \'<button onclick="showToast(\\\'Login feature coming soon\\\')" style="width:100%;background:var(--dk);color:#fff;border:none;padding:12px;border-radius:8px;font-size:14px;font-family:var(--f);font-weight:700;cursor:pointer">Sign In</button>\'+\n        \'</div>\'+\n        \'<div class="card-box">\'+\n          \'<div style="font-weight:600;margin-bottom:12px">My Wishlist (\'+wish.length+\' items)</div>\'+\n          (wishItems||\'<div style="color:var(--t2);font-size:13px">No items in wishlist yet</div>\')+\n        \'</div>\'+\n      \'</div>\'+renderFooter();\n  }\n}\n\nfunction renderFooter(){\n  return \'<footer>\'+\n    \'<div class="fg">\'+\n      \'<div><div class="fb">NNIT.SHOP</div><div class="fd">Your trusted online marketplace. Quality products, fast delivery worldwide.</div></div>\'+\n      \'<div><div class="ft">SHOP</div><span class="fl" onclick="goShop(\\\'electronics\\\')">Electronics</span><span class="fl" onclick="goShop(\\\'fashion\\\')">Fashion</span><span class="fl" onclick="goShop(\\\'home\\\')">Home</span><span class="fl" onclick="goShop(\\\'sports\\\')">Sports</span></div>\'+\n      \'<div><div class="ft">HELP</div><span class="fl">Shipping Info</span><span class="fl">Returns</span><span class="fl">FAQ</span><span class="fl">Contact Us</span></div>\'+\n      \'<div><div class="ft">COMPANY</div><span class="fl" onclick="goPage(\\\'about\\\')">About Us</span><span class="fl">Blog</span><span class="fl">Careers</span><span class="fl">Privacy Policy</span></div>\'+\n    \'</div>\'+\n    \'<div class="fbot"><span>2026 NNIT Shop. All rights reserved.</span><span>Powered by NNIT Technology</span></div>\'+\n  \'</footer>\';\n}\n\nfunction showToast(msg){\n  var e=document.querySelector(".toast");if(e)e.remove();\n  var t=document.createElement("div");t.className="toast";t.textContent=msg;\n  document.body.appendChild(t);setTimeout(function(){t.remove();},3000);\n}\n\nupdateBadges();\ngoHome();\n</script>\n</body>\n</html>\n'
